#include <bits/stdc++.h>
using namespace std;
int n,m;
int dfs(int x,int p){
    if(x==0)
        return 1;
    return dfs(x-1,(p+1)/2)+(1<<(x-p%2));
}
int main(){
    int t;
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        printf("%d\n",dfs(n-1,m%(1<<n-1)));
    }
    scanf("%d",&t);
    return 0;
}
